import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { login, createAdmin } from '../utils/api';
import { LogIn, Mail, Lock, ShieldCheck, UserPlus } from 'lucide-react';

export default function AdminLoginPage() {
  const [mode, setMode] = useState('login'); // 'login' or 'create'
  const [form, setForm] = useState({ email: '', password: '', name: '', phone: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { loginUser } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const res = await login({ email: form.email, password: form.password });
      if (res.data.user.role !== 'admin') {
        setError('Access denied. Admin privileges required.');
        return;
      }
      loginUser(res.data.token, res.data.user);
      navigate('/admin');
    } catch (err) {
      const errorData = err.response?.data;
      let errorMessage = 'Login failed. Please try again.';
      if (errorData?.errors && Array.isArray(errorData.errors)) {
        errorMessage = errorData.errors.map(e => e.msg).join(', ');
      } else if (errorData?.message && typeof errorData.message === 'string') {
        errorMessage = errorData.message;
      }
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await createAdmin({ name: form.name, email: form.email, phone: form.phone, password: form.password });
      setError('Admin created successfully! You can now login.');
      setMode('login');
      setForm({ email: '', password: '', name: '', phone: '' });
    } catch (err) {
      const errorData = err.response?.data;
      let errorMessage = 'Failed to create admin.';
      if (errorData?.errors && Array.isArray(errorData.errors)) {
        errorMessage = errorData.errors.map(e => e.msg).join(', ');
      } else if (errorData?.message && typeof errorData.message === 'string') {
        errorMessage = errorData.message;
      }
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'linear-gradient(135deg,#F8F6F1 0%,#E8F5E9 100%)', padding:24 }}>
      <div style={{ width:'100%', maxWidth:420 }}>
        <div style={{ textAlign:'center', marginBottom:32 }}>
          <div style={{ width:56, height:56, background:'linear-gradient(135deg,#1B4332,#2D6A4F)', borderRadius:14, display:'flex', alignItems:'center', justifyContent:'center', margin:'0 auto 16px' }}>
            <ShieldCheck size={28} color="#F4A261" />
          </div>
          <h1 style={{ fontSize:28, marginBottom:6 }}>Admin {mode === 'login' ? 'Login' : 'Creation'}</h1>
          <p style={{ color:'#6B7280' }}>{mode === 'login' ? 'Access the RozgarKashmir admin panel' : 'Create a new admin account'}</p>
        </div>

        <div style={{ display:'flex', marginBottom:24 }}>
          <button onClick={() => setMode('login')} style={{ flex:1, padding:'10px 0', border:'none', background:mode==='login'?'#1B4332':'#E5E0D5', color:mode==='login'?'white':'#6B7280', borderRadius:'8px 0 0 8px', cursor:'pointer' }}>Login</button>
          <button onClick={() => setMode('create')} style={{ flex:1, padding:'10px 0', border:'none', background:mode==='create'?'#1B4332':'#E5E0D5', color:mode==='create'?'white':'#6B7280', borderRadius:'0 8px 8px 0', cursor:'pointer' }}>Create Admin</button>
        </div>

        <div className="card" style={{ padding:32 }}>
          {error && (
            <div style={{ background:'#FEE2E2', border:'1px solid #FCA5A5', borderRadius:8, padding:'12px 16px', marginBottom:20, color:'#DC2626', fontSize:14 }}>
              {error}
            </div>
          )}
          <form onSubmit={mode === 'login' ? handleLogin : handleCreate} style={{ display:'flex', flexDirection:'column', gap:20 }}>
            {mode === 'create' && (
              <>
                <div className="form-group">
                  <label className="form-label">Full Name</label>
                  <input className="form-input" type="text" value={form.name} onChange={e => setForm({...form, name:e.target.value})} required />
                </div>
                <div className="form-group">
                  <label className="form-label">Phone</label>
                  <input className="form-input" type="tel" value={form.phone} onChange={e => setForm({...form, phone:e.target.value})} required />
                </div>
              </>
            )}
            <div className="form-group">
              <label className="form-label">Email Address</label>
              <div style={{ position:'relative' }}>
                <Mail size={16} style={{ position:'absolute', left:12, top:'50%', transform:'translateY(-50%)', color:'#9CA3AF' }} />
                <input className="form-input" type="email" placeholder="admin@example.com" value={form.email} onChange={e => setForm({...form, email:e.target.value})} style={{ paddingLeft:38 }} required />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">Password</label>
              <div style={{ position:'relative' }}>
                <Lock size={16} style={{ position:'absolute', left:12, top:'50%', transform:'translateY(-50%)', color:'#9CA3AF' }} />
                <input className="form-input" type="password" placeholder="Enter password" value={form.password} onChange={e => setForm({...form, password:e.target.value})} style={{ paddingLeft:38 }} required />
              </div>
            </div>
            <button type="submit" className="btn btn-primary" disabled={loading} style={{ width:'100%', padding:'12px 0' }}>
              {loading ? (mode === 'login' ? 'Logging in...' : 'Creating...') : (mode === 'login' ? 'Login as Admin' : 'Create Admin')}
            </button>
          </form>
          {mode === 'login' && (
            <div style={{ textAlign:'center', marginTop:20 }}>
              <Link to="/login" style={{ color:'#6B7280', fontSize:14 }}>Back to User Login</Link>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
